class Solution {
    public List<Integer> beautifulIndices(String s, String a, String b, int k) {
        int[] count = new int[26];
        int[] diff = new int[26];

        for (int i = 0; i < s.length(); i++) {
            count[s.charAt(i) - 'a']++;
            diff[s.charAt(i) - 'a'] = Math.abs(count[s.charAt(i) - 'a'] - count[a.length() - 1] + diff[a.length() - 1];
        }

        List<Integer> result = new ArrayList<>();
        for (int i = 0; i < s.length(); i++) {
            if (diff[s.charAt(i) - 'a'] <= k) {
                result.add(i);
            }
        }

        return result;
    }
}
